//! The Ulysses pact, end to end through `ops::spawn`.
//!
//! When a spawn requests an oath as RAW TERMS JSON, the agent cryptographically
//! SWEARS it: it signs the terms into a UCAN oath-token with its OWN
//! freshly-minted keypair (iss = aud = agent DID — it ties itself to the mast),
//! writes the signed token 0600, and hands THAT token's *path* to
//! `monster-guard delegate --oath`. This test proves the swarm side of that flow
//! without the real guard runtime (a sibling crate): a fake `monster-guard`
//! binary captures the args it was called with, so we can assert the agent's own
//! signed oath-token path is what reached `--oath`.
//!
//! Isolated in a per-pid temp `$MONSTER_GUARD_HOME` (its own process, so the env
//! var cannot race another test), and cleaned up at the end.

use std::os::unix::fs::PermissionsExt;
use std::path::PathBuf;

use a0n_auth::ucan::issue;
use a0n_auth::{verify_chain, Capability, IssueOptions};

use monster_swarm::budget::Caste;
use monster_swarm::ops::{self, SpawnRequest, DEFAULT_GRANT_TTL_SECS};
use monster_swarm::store;

/// Write a fake `monster-guard` that records `delegate`'s args (so we can assert
/// the oath path) and exits 0 for everything (delegate + run). For `run` it
/// stays alive briefly so the supervisor pid is "live" when the ledger is saved.
fn fake_guard(dir: &PathBuf, capture: &PathBuf) -> PathBuf {
    let bin = dir.join("monster-guard");
    let script = format!(
        "#!/bin/sh\n\
         if [ \"$1\" = \"delegate\" ]; then\n\
         \techo \"$@\" >> {capture}\n\
         \texit 0\n\
         fi\n\
         if [ \"$1\" = \"run\" ]; then\n\
         \texec sleep 30\n\
         fi\n\
         exit 0\n",
        capture = capture.display()
    );
    std::fs::write(&bin, script).unwrap();
    std::fs::set_permissions(&bin, std::fs::Permissions::from_mode(0o755)).unwrap();
    bin
}

/// A fake node binary in an allowlisted dir (resolve_node only checks it is an
/// allowlisted, canonicalizable file — it is never executed; the fake guard's
/// `run` ignores it).
fn fake_node(dir: &PathBuf) -> PathBuf {
    let node = dir.join("fake-node");
    std::fs::write(&node, "#!/bin/sh\nexit 0\n").unwrap();
    std::fs::set_permissions(&node, std::fs::Permissions::from_mode(0o755)).unwrap();
    node
}

#[test]
fn spawn_with_raw_terms_swears_a_signed_oath_and_passes_it_to_guard() {
    let home = std::env::temp_dir().join(format!("monster-swarm-oathpact-{}", std::process::id()));
    let _ = std::fs::remove_dir_all(&home);
    std::fs::create_dir_all(&home).unwrap();
    std::env::set_var("MONSTER_GUARD_HOME", &home);

    let bindir = home.join("bin");
    std::fs::create_dir_all(&bindir).unwrap();
    let capture = home.join("delegate-args.txt");
    let guard = fake_guard(&bindir, &capture);
    let _node = fake_node(&bindir);
    std::env::set_var("MONSTER_GUARD_BIN", &guard);
    std::env::set_var("MONSTER_SWARM_NODES", &bindir);

    // Root-rooted capability granting agent/spawn + agent/reap (verified by
    // ops::authorize) — reap at the end uses the same token.
    let root = store::ensure_root().expect("root");
    let caps = vec![
        Capability { can: "agent/spawn".into(), with: "agent:fleet".into(), constraints: None },
        Capability { can: "agent/reap".into(), with: "agent:fleet".into(), constraints: None },
    ];
    let ucan = issue(&root, root.did(), &caps, 3600, &IssueOptions::default()).expect("ucan");

    // Spawn with RAW oath terms (inline JSON, not a token, not a path).
    let raw_terms = r#"{ "oath": "I stay within my caps and do not exfiltrate.", "max_caps": ["net"], "ttl_max_secs": 3600 }"#;
    let req = SpawnRequest {
        ucan: ucan.clone(),
        node: "fake-node".into(),
        id: Some("ulysses".into()),
        caste: Caste::Scout,
        caps: vec!["net".into()],
        lease_secs: 60,
        max_secs: None,
        grant_ttl_secs: DEFAULT_GRANT_TTL_SECS,
        node_args: vec![],
        qspec: None,
        oath: Some(raw_terms.to_string()),
        teleport: None,
    };
    let spawned = ops::spawn(req).expect("spawn with raw oath terms");
    assert_eq!(spawned.id, "ulysses");

    // (1) A signed oath-token was written to the canonical 0600 path.
    let token_path = store::oath_token_path("ulysses");
    assert!(token_path.is_file(), "the signed oath-token must be written to disk");
    let mode = std::fs::metadata(&token_path).unwrap().permissions().mode() & 0o777;
    assert_eq!(mode, 0o600, "oath-token must be owner-only (0600)");
    let token = std::fs::read_to_string(&token_path).unwrap();

    // (2) The token is a verify_chain-valid Ulysses oath: iss == aud == agent
    //     DID, and the leaf fct == the sworn terms.
    let res = verify_chain(&token, None, None);
    assert!(res.valid, "the sworn oath-token must verify: {:?}", res.error);
    let leaf = res.chain.first().expect("leaf");
    assert_eq!(leaf.iss, leaf.aud, "Ulysses: the swearer is the bound (iss == aud)");
    let fleet = store::load_fleet();
    let rec = fleet.find("ulysses").expect("ledger record");
    assert_eq!(leaf.iss, rec.did, "the oath was signed by the agent's own DID");
    assert_eq!(
        leaf.fct.as_ref().expect("fct")["oath"],
        "I stay within my caps and do not exfiltrate."
    );
    assert_eq!(leaf.att[0].can, "oath/uphold");
    assert_eq!(leaf.att[0].with, "agent:self:ulysses");

    // (3) The ledger records the crypto proof: signed, by the agent's DID, and
    //     the recorded oath is the signed-token path.
    assert!(rec.oath_signed, "the Ulysses pact is recorded as signed");
    assert_eq!(rec.oath_sworn_by.as_deref(), Some(rec.did.as_str()));
    assert_eq!(rec.oath.as_deref(), Some(token_path.to_str().unwrap()));

    // (4) The guard's `delegate` was handed the agent's own signed-token PATH on
    //     `--oath` (not the raw terms) — the seam to monster-guard.
    let args = std::fs::read_to_string(&capture).expect("delegate was called");
    let token_path_str = token_path.to_str().unwrap();
    assert!(
        args.contains("--oath") && args.contains(token_path_str),
        "delegate must receive --oath <signed-token-path>; got: {args}"
    );

    // The fleet frame surfaces the crypto proof.
    let oaths = fleet.oaths();
    let entry = oaths.iter().find(|e| e.id == "ulysses").expect("oath entry");
    assert!(entry.signed);
    assert_eq!(entry.sworn_by.as_deref(), Some(rec.did.as_str()));

    // Reap removes the token (the fake guard's revoke exits 0).
    ops::reap(&ucan, "ulysses").expect("reap the scout");
    assert!(
        !store::oath_token_path("ulysses").exists(),
        "reap must remove the oath-token (like the keyfile)"
    );

    std::env::remove_var("MONSTER_GUARD_HOME");
    std::env::remove_var("MONSTER_GUARD_BIN");
    std::env::remove_var("MONSTER_SWARM_NODES");
    let _ = std::fs::remove_dir_all(&home);
}
